import React, { useEffect, useState } from 'react';
import Card from './Card'; 
import '../style/CardWithData.css';
import { useFilterContext } from '../ContextApi/FilterApi';
import { useOrderContext } from '../../Cart_Page/contextAPI/OrderCartContext';

const CardWithData = () => {
    const [fullData, setFullData] = useState([]); // Store all data here
    const [data, setData] = useState([]); // Store filtered data here
    const context = useFilterContext();
    const OrderContextT = useOrderContext();

    useEffect(() => {
        const fetchData = async () => {
            try {
                const response = await fetch("http://localhost:8000/Menu");
                OrderContextT.setMenu(response);
                
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }

                const result = await response.json();
                console.log("Fetched data:", result);

                setFullData(Array.isArray(result) ? result : []); // Store the full data
                setData(Array.isArray(result) ? result : []); // Initialize filtered data
            } catch (error) {
                console.error("Error fetching data: ", error);
            }
        };

        fetchData();
    }, []); // Fetch data only once when component mounts

    useEffect(() => {
        // Filter data based on context.category
        if (context.category) {
            const filteredData = fullData.filter(item => item.category === context.category);
            setData(filteredData);
        } else {
            setData(fullData); // Reset to all data if no filter is applied
        }
    }, [context.category, fullData]); // Re-run only if category changes

    return (
        <div className="cards-container">
            {data.length === 0 ? (
                <p>Loading data...</p>
            ) : (
                data.map((item) => (
                    <Card
                        key={item.id} 
                        name={item.item}
                        price={item.price}
                        description={item.discription} // Corrected spelling to `description`
                    />
                ))
            )}
        </div>
    );
};

export default CardWithData;
